sql:
SELECT directory_id, directory_name, status
FROM directories
WHERE status = 'active';

SELECT assembly_name
FROM assemblies
WHERE assembly_id NOT IN (
    SELECT assembly_id
    FROM issues
);

SELECT assembly_name, assembly_version, last_checked_at
FROM assemblies
WHERE last_checked_at < '2023-01-01';

SELECT DISTINCT user_name 
FROM users 
WHERE user_id IN (SELECT DISTINCT resolved_by_user_id FROM issues WHERE resolved_by_user_id IS NOT NULL);

SELECT COUNT(*) AS TotalOutdatedAssemblies
FROM assemblies
WHERE is_outdated = 1;

